// ============================================
// NIVEL 1: Clasificare din filename (regex)
// ============================================

const items = $input.all();
const results = [];

for (const item of items) {
  const filename = item.json.fileName || item.json.name || '';
  const fname = filename.toLowerCase();

  let category = null;
  let confidence = 0;
  let method = 'filename';

  // Regula speciala: "sanitar" = AVIZ_SANITAR (100% unic)
  if (/sanitar/i.test(fname)) {
    category = 'AVIZ_SANITAR';
    confidence = 0.99;
  }
  // Aviz Tehnic + Agrement (ambele prezente)
  else if (/aviz.*agrement|agrement.*aviz|avt.*agt|agt.*avt/i.test(fname)) {
    category = 'AVIZ_TEHNIC_SI_AGREMENT';
    confidence = 0.95;
  }
  // ISO certificates
  else if (/iso\s*(?:9001|14001|45001|50001)/i.test(fname)) {
    category = 'ISO';
    confidence = 0.99;
  }
  // Agrement tehnic
  else if (/\bagt\b|agrement/i.test(fname) && !/aviz/i.test(fname)) {
    category = 'AGREMENT';
    confidence = 0.95;
  }
  // Aviz tehnic (fara sanitar, fara agrement)
  else if (/\bavt\b|aviz\s*tehnic/i.test(fname) && !/sanitar/i.test(fname) && !/agrement/i.test(fname)) {
    category = 'AVIZ_TEHNIC';
    confidence = 0.95;
  }
  // Fisa tehnica
  else if (/\bft\b|fi[sș][aă]\s*tehnic/i.test(fname)) {
    category = 'FISA_TEHNICA';
    confidence = 0.95;
  }
  // Declaratie conformitate
  else if (/\bdc\b(?!\s*-)|declara[tț]i[ea]\s*(?:de\s*)?conformitate/i.test(fname)) {
    category = 'DECLARATIE_CONFORMITATE';
    confidence = 0.90;
  }
  // Declaratie performanta
  else if (/\bdop\b|declara[tț]i[ea]\s*(?:de\s*)?performan/i.test(fname)) {
    category = 'DECLARATIE_PERFORMANTA';
    confidence = 0.95;
  }
  // CE
  else if (/\bce\b/i.test(fname) && !/certificat|cert\b/i.test(fname)) {
    category = 'CE';
    confidence = 0.85;
  }
  // CUI
  else if (/\bcui\b/i.test(fname)) {
    category = 'CUI';
    confidence = 0.95;
  }
  // Certificat calitate
  else if (/\bcc\b|certificat.*calitate/i.test(fname)) {
    category = 'CERTIFICAT_CALITATE';
    confidence = 0.90;
  }
  // Certificat garantie
  else if (/\bcg\b|certificat.*garan[tț]/i.test(fname)) {
    category = 'CERTIFICAT_GARANTIE';
    confidence = 0.95;
  }
  // Autorizatie distributie
  else if (/autoriz|authorization/i.test(fname)) {
    category = 'AUTORIZATIE_DISTRIBUTIE';
    confidence = 0.90;
  }

  results.push({
    json: {
      ...item.json,
      filename: filename,
      category_level1: category,
      confidence_level1: confidence,
      method: method,
      needs_ai: category === null || confidence < 0.85
    }
  });
}

return results;

// ============================================
// Pregatire pentru AI: extrage text din PDF
// ============================================
// Nota: In n8n, extragerea de text din PDF se face
// fie cu Extract from File node, fie cu un Code node
// care foloseste o librarie PDF.
//
// Aceasta este o versiune simplificata.
// In productie, foloseste 'Extract from File' node
// sau un HTTP Request catre un serviciu OCR.

const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      ...item.json,
      // Textul extras va fi populat de nodul anterior
      // sau de un serviciu OCR extern
      extracted_text: item.json.extracted_text || '',
      ai_prompt: `Clasifica urmatorul document PDF.\n\nFilename: ${item.json.filename}\nNumar pagini: ${item.json.page_count || 'necunoscut'}\nText extras (primele 2000 caractere):\n${(item.json.extracted_text || 'Nu s-a putut extrage text - document scanat').substring(0, 2000)}`
    }
  });
}

return results;

// ============================================
// Parseaza raspunsul AI si extrage categoria
// ============================================

const items = $input.all();
const results = [];

for (const item of items) {
  let category = 'ALTELE';
  let confidence = 0;
  let reasoning = '';

  try {
    const aiResponse = item.json.choices?.[0]?.message?.content || '';
    // Parse JSON from AI response
    const jsonMatch = aiResponse.match(/\{[^}]+\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      category = parsed.category || 'ALTELE';
      confidence = parsed.confidence || 0;
      reasoning = parsed.reasoning || '';
    }
  } catch (e) {
    reasoning = 'AI parse error: ' + e.message;
  }

  // Validare: categoria trebuie sa fie una din cele 14
  const validCategories = [
    'AGREMENT', 'AUTORIZATIE_DISTRIBUTIE', 'AVIZ_TEHNIC_SI_AGREMENT',
    'AVIZ_TEHNIC', 'AVIZ_SANITAR', 'CE', 'CERTIFICAT_CALITATE',
    'CERTIFICAT_GARANTIE', 'CUI', 'DECLARATIE_CONFORMITATE',
    'DECLARATIE_PERFORMANTA', 'FISA_TEHNICA', 'ISO', 'ALTELE'
  ];

  if (!validCategories.includes(category)) {
    category = 'ALTELE';
    confidence = 0.3;
  }

  results.push({
    json: {
      filename: item.json.filename || $('4a. Pregatire Text pentru AI').item.json.filename,
      filePath: item.json.filePath || $('4a. Pregatire Text pentru AI').item.json.filePath,
      category: category,
      confidence: confidence,
      reasoning: reasoning,
      method: 'ai_classification'
    }
  });
}

return results;

// ============================================
// Formatare rezultate din clasificarea filename
// (pentru documentele care NU au nevoie de AI)
// ============================================

const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      filename: item.json.filename,
      filePath: item.json.filePath,
      category: item.json.category_level1,
      confidence: item.json.confidence_level1,
      reasoning: 'Classified by filename pattern',
      method: 'filename_regex'
    }
  });
}

return results;

// ============================================
// FOLDER MAPPING: categoria -> subfolder name
// ============================================

const FOLDER_MAP = {
  'AGREMENT': 'Agrement',
  'AUTORIZATIE_DISTRIBUTIE': 'Autorizatii de comercializare sau de distributie',
  'AVIZ_TEHNIC_SI_AGREMENT': 'Aviz Tehnic + Agrement',
  'AVIZ_TEHNIC': 'Aviz tehnic',
  'AVIZ_SANITAR': 'Avize Sanitare',
  'CE': 'CE',
  'CERTIFICAT_CALITATE': 'Certificat Calitate',
  'CERTIFICAT_GARANTIE': 'Certificat Garantie',
  'CUI': 'Cui',
  'DECLARATIE_CONFORMITATE': 'Declaratii conformitate',
  'DECLARATIE_PERFORMANTA': 'Declaratie de Performanta',
  'FISA_TEHNICA': 'Fisa Tehnica',
  'ISO': 'Iso',
  'ALTELE': 'Z.Altele'
};

const items = $input.all();
const results = [];

for (const item of items) {
  const category = item.json.category || 'ALTELE';
  const targetFolder = FOLDER_MAP[category] || 'Z.Altele';
  const outputBase = $('Manual Trigger').item.json.output_folder || '/data/output';

  results.push({
    json: {
      ...item.json,
      target_folder: targetFolder,
      target_path: `${outputBase}/${targetFolder}/${item.json.filename}`
    }
  });
}

return results;

// ============================================
// Muta fisierele in folderele corecte
// ============================================
// Nota: In productie, inlocuieste cu 'Move File' node
// sau cu comenzi shell specifice.

const { execSync } = require('child_process');
const items = $input.all();
const results = [];
const outputBase = items[0]?.json?.target_path?.split('/').slice(0, -2).join('/') || '/data/output';

// Creeaza folderele daca nu exista
const folders = [...new Set(items.map(i => i.json.target_folder))];
for (const folder of folders) {
  try {
    execSync(`mkdir -p "${outputBase}/${folder}"`);
  } catch (e) {}
}

for (const item of items) {
  const src = item.json.filePath;
  const dst = item.json.target_path;
  let moved = false;

  if (src && dst) {
    try {
      execSync(`cp "${src}" "${dst}"`);
      moved = true;
    } catch (e) {
      // File move failed
    }
  }

  results.push({
    json: {
      ...item.json,
      moved: moved
    }
  });
}

return results;

// ============================================
// Genereaza raport Excel (CSV format)
// ============================================

const items = $input.all();

// Header
let csv = 'Nr.,Filename,Categorie,Confidence,Metoda,Folder Destinatie,Reasoning\n';

// Sort by category
const sorted = [...items].sort((a, b) => 
  (a.json.category || '').localeCompare(b.json.category || '')
);

for (let i = 0; i < sorted.length; i++) {
  const item = sorted[i].json;
  const row = [
    i + 1,
    `"${(item.filename || '').replace(/"/g, '""')}"`,
    item.category || 'ALTELE',
    (item.confidence || 0).toFixed(2),
    item.method || 'unknown',
    `"${item.target_folder || ''}"`,
    `"${(item.reasoning || '').replace(/"/g, '""')}"`
  ].join(',');
  csv += row + '\n';
}

// Summary
csv += '\n\nSUMAR PER CATEGORIE\n';
csv += 'Categorie,Numar Documente\n';
const counts = {};
for (const item of items) {
  const cat = item.json.category || 'ALTELE';
  counts[cat] = (counts[cat] || 0) + 1;
}
for (const [cat, count] of Object.entries(counts).sort()) {
  csv += `${cat},${count}\n`;
}
csv += `TOTAL,${items.length}\n`;

return [{
  json: {
    total_documents: items.length,
    categories_found: Object.keys(counts).length,
    summary: counts
  },
  binary: {
    data: {
      data: Buffer.from(csv).toString('base64'),
      mimeType: 'text/csv',
      fileName: `Raport_Clasificare_${new Date().toISOString().split('T')[0]}.csv`
    }
  }
}];
